#include &lt;stdint.h&gt;

// 1. Import the dynamic symbols calculated by the Linker
extern uint32_t _sdata;
extern uint32_t _edata;
extern uint32_t _la_data; // Load Address (Flash)

extern uint32_t _sbss;
extern uint32_t _ebss;

// The entry point for our C application
extern int main(void);

// 2. The True Hardware Entry Point
void Reset_Handler(void) {
    // A. Copy the .data segment from Flash ROM (LMA) to SRAM (VMA)
    uint32_t *ram_ptr = &_sdata;    // Destination in RAM
    uint32_t *flash_ptr = &_la_data; // Source in Flash

    while (ram_ptr < &_edata) {
        *ram_ptr++ = *flash_ptr++;
    }

    // B. Zero out the .bss segment in SRAM
    // If we skip this, uninitialized variables hold random garbage!
    ram_ptr = &_sbss;
    while (ram_ptr < &_ebss) {
        *ram_ptr++ = 0;
    }

    // C. Initialize hardware clocks or FPU here if needed...

    // D. Finally, call the standard C application
    main();

    // E. Fallback: If main() ever accidentally returns, we must not execute 
    // random memory. We trap the CPU in an infinite loop.
    while (1) {}
}

extern uint32_t _sdata;
extern uint32_t _edata;

void verify_memory_size() {
    // Engineer wants to calculate how many bytes the .data segment consumes
    // DANGER: Massive logical error resulting in random math
    uint32_t size = _edata - _sdata;

    printf("Data Size: %u bytes\n", size);
}
